const crypto = require('crypto');

const html = $input.item.json.data || $input.item.json.body || '';
const sourceId = $input.item.json.source_id;
const sourceDbId = $input.item.json.id;
const oldHash = $input.item.json.content_hash || '';

// Clean HTML for consistent hashing
const cleanHtml = html
  .replace(/\s+/g, ' ')  // Normalize whitespace
  .replace(/<!--.*?-->/g, '')  // Remove comments
  .trim();

// Calculate SHA-256 hash
const newHash = crypto
  .createHash('sha256')
  .update(cleanHtml)
  .digest('hex');

// Detect change
const hasChanged = oldHash && newHash !== oldHash;

return {
  json: {
    sourceDbId,
    sourceId,
    source_type: $input.item.json.source_type,
    title: $input.item.json.title,
    url: $input.item.json.url,
    target_page: $input.item.json.target_page,
    target_section: $input.item.json.target_section,
    oldHash,
    newHash,
    hasChanged,
    oldContent: oldHash ? 'Previous version content' : '',
    newContent: cleanHtml.substring(0, 5000),
    priority: $input.item.json.priority
  }
};

// Parse AI analysis JSON from command output
const stdout = $input.item.json.stdout || '';

// Extract JSON from output (remove ANSI colors and log messages)
const jsonMatch = stdout.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error('No valid JSON found in AI response');
}

const analysis = JSON.parse(jsonMatch[0]);

return {
  json: {
    changeRecordId: $('Create Change Record').item.json.id,
    sourceId: $('Calculate Content Hash').item.json.sourceId,
    title: $('Calculate Content Hash').item.json.title,
    url: $('Calculate Content Hash').item.json.url,
    targetPage: $('Calculate Content Hash').item.json.target_page,
    targetSection: $('Calculate Content Hash').item.json.target_section,
    priority: $('Calculate Content Hash').item.json.priority,
    analysis: analysis,
    summary: analysis.summary,
    severity: analysis.severity,
    affectedPages: JSON.stringify(analysis.affected_pages),
    impactAssessment: analysis.impact_assessment,
    updatedHtml: analysis.updated_html,
    recommendations: analysis.recommendations
  }
};

// Aggregate all checked sources
const sources = $input.all();
const totalSources = sources.length;
const changedSources = sources.filter(s => s.json.hasChanged).length;
const unchangedSources = totalSources - changedSources;

return {
  json: {
    totalSources,
    changedSources,
    unchangedSources,
    checkTime: new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })
  }
};

